data: {"type":"response.code_interpreter_call_code.done","code":"import numpy as np\r\nimport matplotlib.pyplot as plt\r\nfrom matplotlib.backends.backend_pdf import PdfPages\r\n\r\n# Mandelbrot set parameters\r\nwidth, height = 800, 800\r\nxmin, xmax, ymin, ymax = -2.0, 1.0, -1.5, 1.5\r\nmax_iter = 100\r\n\r\n# Create image grid\r\nx = np.linspace(xmin, xmax, width)\r\ny = np.linspace(ymin, ymax, height)\r\nX, Y = np.meshgrid(x, y)\r\nC = X + 1j * Y\r\nZ = np.zeros_like(C)\r\nmandelbrot_img = np.zeros(C.shape, dtype=int)\r\n\r\nfor i in range(max_iter):\r\n    mask = np.abs(Z) <= 2\r\n    Z[mask] = Z[mask] ** 2 + C[mask]\r\n    mandelbrot_img[mask] = i\r\n\r\n# Plotting\r\nfig, ax = plt.subplots(figsize=(8, 8))\r\nax.imshow(mandelbrot_img, extent=(xmin, xmax, ymin, ymax), cmap='hot')\r\nax.set_title(\"Mandelbrot Set\")\r\nax.axis('off')\r\n\r\n# Save to PDF\r\npdf_path = '/mnt/data/mandelbrot_set.pdf'\r\nwith PdfPages(pdf_path) as pdf:\r\n    pdf.savefig(fig)\r\nplt.close(fig)\r\n\r\npdf_path","item_id":"ci_04e1c3bd01f753c10069b30ef76ff88197953ae9e55c912082","output_index":0,"sequence_number":279}

